suspend fun <T> retryWithTimeout(
    times: Int = 3,
    initialDelay: Long = 1000,
    timeoutMillis: Long = 5000,
    block: suspend () -> T
): T {
    var currentDelay = initialDelay
    repeat(times - 1) {
        try {
            return withTimeout(timeoutMillis) { block() }
        } catch (e: Exception) {
            if (e is TimeoutCancellationException || 
                e is IOException ||
                e is HttpException) {
                delay(currentDelay)
                currentDelay *= 2
            } else {
                throw e
            }
        }
    }
    return withTimeout(timeoutMillis) { block() }
}
