### 1.3 智谱 GLM (ChatGLM/GLM-4)

**官方文档链接：**
- [智谱AI开放文档](https://docs.bigmodel.cn/)
- [HTTP API 调用文档](https://docs.bigmodel.cn/cn/guide/develop/http/introduction)
- [官方 Java SDK](https://github.com/MetaGLM/zhipuai-sdk-java-v4)
- [快速开始指南](https://docs.bigmodel.cn/cn/guide/start/quick-start)

**基本调用示例（使用 HTTP API）：**

```kotlin
import okhttp3.*
import okhttp3.MediaType.Companion.toMediaType
import okhttp3.RequestBody.Companion.toRequestBody
import org.json.JSONArray
import org.json.JSONObject
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.withContext
import java.util.*
import javax.crypto.Mac
import javax.crypto.spec.SecretKeySpec
import java.util.Base64

class ZhipuClient(private val apiKey: String) {

    private val client = OkHttpClient()
    private val JSON = "application/json; charset=utf-8".toMediaType()

    // 生成 JWT Token
    private fun generateToken(apiKey: String): String {
        val parts = apiKey.split(".")
        val id = parts[0]
        val secret = parts[1]

        val header = JSONObject().apply {
            put("alg", "HS256")
            put("sign_type", "SIGN")
        }

        val payload = JSONObject().apply {
            put("api_key", id)
            put("exp", System.currentTimeMillis() / 1000 + 3600)
            put("timestamp", System.currentTimeMillis())
        }

        val encodedHeader = Base64.getEncoder().encodeToString(header.toString().toByteArray())
        val encodedPayload = Base64.getEncoder().encodeToString(payload.toString().toByteArray())

        val signature = hmacSha256("$encodedHeader.$encodedPayload", secret)

        return "$encodedHeader.$encodedPayload.$signature"
    }

    private fun hmacSha256(data: String, secret: String): String {
        val mac = Mac.getInstance("HmacSHA256")
        val secretKeySpec = SecretKeySpec(secret.toByteArray(), "HmacSHA256")
        mac.init(secretKeySpec)
        return Base64.getUrlEncoder().withoutPadding().encodeToString(mac.doFinal(data.toByteArray()))
    }

    suspend fun chat(prompt: String): String = withContext(Dispatchers.IO) {
        val token = generateToken(apiKey)

        val jsonBody = JSONObject().apply {
            put("model", "glm-4")
            put("messages", JSONArray().apply {
                put(JSONObject().apply {
                    put("role", "user")
                    put("content", prompt)
                })
            })
        }

        val request = Request.Builder()
            .url("https://open.bigmodel.cn/api/paas/v4/chat/completions")
            .addHeader("Authorization", "Bearer $token")
            .addHeader("Content-Type", "application/json")
            .post(jsonBody.toString().toRequestBody(JSON))
            .build()

        val response = client.newCall(request).execute()
        val jsonResponse = JSONObject(response.body?.string())
        jsonResponse.getJSONArray("choices")
            .getJSONObject(0)
            .getJSONObject("message")
            .getString("content")
