### 3.2 带超时控制的并行调用

```kotlin
import kotlinx.coroutines.*
import kotlin.time.Duration
import kotlin.time.Duration.Companion.seconds

class TimeoutLLMOrchestrator(
    private val clients: Map<String, Any> // Provider -> Client
) {

    suspend fun chatWithTimeouts(
        prompt: String,
        timeout: Duration = 30.seconds
    ): Map<String, LLMResponse> = coroutineScope {

        val deferredResults = clients.mapKeys { (provider, _) ->
            async {
                withTimeout(timeout) {
                    callLLMSafely(provider, prompt)
                }
            }
        }

        deferredResults.mapValues { (_, deferred) ->
            try {
                deferred.await()
            } catch (e: TimeoutCancellationException) {
                LLMResponse("unknown", "", 0, false, e)
            }
        }
    }

    private suspend fun callLLMSafely(
        provider: String,
        prompt: String
    ): LLMResponse = withContext(Dispatchers.IO) {
        val startTime = System.currentTimeMillis()
        try {
            val response = when (provider) {
                "OpenAI" -> (clients["OpenAI"] as OpenAIClient).chat(prompt)
                "Claude" -> (clients["Claude"] as ClaudeClient).chat(prompt)
                "Gemini" -> (clients["Gemini"] as GeminiClient).chat(prompt)
                // 其他提供商...
                else -> throw IllegalArgumentException("Unknown provider: $provider")
            }
            val latency = System.currentTimeMillis() - startTime
            LLMResponse(provider, response, latency, true)
        } catch (e: Exception) {
            val latency = System.currentTimeMillis() - startTime
            LLMResponse(provider, "", latency, false, e)
        }
    }
}
