/**
 * LLM 并行调用编排器
 *
 * 负责同时调用多个已配置的 LLM 提供商，并从返回结果中选择最优的
 */
class LLMOrchestrator(
    private val configRepository: LLMConfigRepository
) {
    private val comparator = ResultComparator()

    /**
     * 并行抽取传票信息
     * @param pdfText PDF 提取的文本
     * @param ocrText OCR 识别的文本（可选）
     * @param timeout 超时时间（秒）
     * @return 最优抽取结果
     */
    suspend fun extractSummonsParallel(
        pdfText: String,
        ocrText: String? = null,
        timeout: Long = 30
    ): LLMResult? = coroutineScope {
        val providers = createProviders()
        if (providers.isEmpty()) return@coroutineScope null

        val results = providers.map { provider ->
            async(Dispatchers.IO) {
                val startTime = System.currentTimeMillis()
                try {
                    withTimeout(timeout.seconds) {
                        val extraction = provider.extractFromPdf(pdfText, ocrText)
