                        provider = provider.getProviderName(),
                        error = e
                    )
                }
            }
        }.awaitAll()

        comparator.selectBest(results)
    }

    /**
     * 并行从短信抽取信息
     * @param smsBody 短信内容
     * @param timeout 超时时间（秒）
     * @return 最优抽取结果
     */
    suspend fun extractFromSmsParallel(
        smsBody: String,
