                    withTimeout(timeout.seconds) {
                        val extraction = provider.extractFromSms(smsBody)
                        val latency = System.currentTimeMillis() - startTime
                        LLMResult.success(
                            provider = provider.getProviderName(),
                            response = extraction.getOrNull() ?: SummonsExtraction(),
                            latency = latency
                        )
                    }
                } catch (e: Exception) {
                    LLMResult.failure(
                        provider = provider.getProviderName(),
