                    )
                }
            }
        }.awaitAll()

        comparator.selectBest(results)
    }

    /**
     * 竞速模式：返回第一个成功的结果
     * @param pdfText PDF 提取的文本
     * @param ocrText OCR 识别的文本（可选）
     * @param timeout 超时时间（秒）
     * @return 第一个成功的结果
     */
    suspend fun extractSummonsRace(
        pdfText: String,
        ocrText: String? = null,
        timeout: Long = 30
    ): LLMResult? = coroutineScope {
        val providers = createProviders()
        if (providers.isEmpty()) return@coroutineScope null

        val deferred = providers.map { provider ->
            async(Dispatchers.IO) {
                try {
                    withTimeout(timeout.seconds) {
                        provider.extractFromPdf(pdfText, ocrText)
                    }
                } catch (e: Exception) {
                    Result.failure<SummonsExtraction>(e)
                }
            }
        }

        // 等待第一个成功的结果
        for (d in deferred) {
            val result = d.await()
            if (result.isSuccess && result.getOrNull()?.isValid() == true) {
                return@coroutineScope LLMResult.success(
                    provider = "Race Winner",
                    response = result.getOrNull()!!,
                    latency = 0
                )
            }
        }

        // 如果没有成功的，返回 null
        null
    }

    /**
     * 根据配置创建所有已启用的 Provider
     */
    private suspend fun createProviders(): List<BaseLLMProvider> = withContext(Dispatchers.IO) {
        val providers = mutableListOf<BaseLLMProvider>()

        for (providerType in LLMProvider.getAllProviders()) {
            val config = configRepository.getConfig(providerType).first()
            if (!config.enabled || config.apiKey.isBlank()) {
                continue
            }

            val provider = when (providerType) {
                LLMProvider.WENXIN -> {
                    if (config.secretKey.isNullOrBlank()) continue
                    WenxinProvider(
                        apiKey = config.apiKey,
                        secretKey = config.secretKey,
                        enabled = config.enabled
                    )
                }
                LLMProvider.QWEN -> QwenProvider(
                    apiKey = config.apiKey,
                    enabled = config.enabled
                )
                LLMProvider.ZHIPU -> ZhipuProvider(
                    apiKey = config.apiKey,
                    enabled = config.enabled
                )
                LLMProvider.OPENAI -> OpenAIProvider(
                    apiKey = config.apiKey,
                    enabled = config.enabled
                )
                LLMProvider.CLAUDE -> ClaudeProvider(
                    apiKey = config.apiKey,
                    enabled = config.enabled
                )
                LLMProvider.GEMINI -> GeminiProvider(
                    apiKey = config.apiKey,
                    enabled = config.enabled
                )
                LLMProvider.MISTRAL -> MistralProvider(
                    apiKey = config.apiKey,
