     */
    suspend fun hasConfiguredProvider(): Boolean {
        return configRepository.hasAnyConfiguredProvider().first()
    }

    /**
     * 获取已启用的提供商列表
     */
    suspend fun getEnabledProviders(): List<LLMProvider> {
        return configRepository.getEnabledProviders().first()
    }

    companion object {
        @Volatile
        private var INSTANCE: LLMOrchestrator? = null

        fun getInstance(configRepository: LLMConfigRepository): LLMOrchestrator {
            return INSTANCE ?: synchronized(this) {
                INSTANCE ?: LLMOrchestrator(configRepository).also { INSTANCE = it }
