package com.shanfuchun.courtassistant.sms

import android.content.Context
import android.content.Intent
import android.util.Log
import androidx.core.content.FileProvider
import com.shanfuchun.courtassistant.App
import com.shanfuchun.courtassistant.data.AppDatabase
import com.shanfuchun.courtassistant.data.SmsRecord
import com.shanfuchun.courtassistant.service.CalendarHelper
import com.shanfuchun.courtassistant.service.PdfDownloader
import com.shanfuchun.courtassistant.service.TextParser
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.delay
import kotlinx.coroutines.withContext

object SmsProcessor {
    private const val TAG = "CourtAssistant"

    suspend fun process(context: Context, db: AppDatabase, sms: SmsRecord) {
        Log.d(TAG, "SmsProcessor: processing sms id=${sms.id}")
        val info = TextParser.parse(sms.body)
        Log.d(TAG, "SmsProcessor: parsed info: time=${info.hearingTime} court=${info.courtName} case=${info.caseNo}")

        // 回写 courtName/partyName 到短信记录
        if (info.courtName.isNotEmpty() || info.partyName.isNotEmpty()) {
            db.smsDao().update(sms.copy(courtName = info.courtName, partyName = info.partyName))
        }

        // 同步开庭信息到日历
        if (info.hearingTime > 0) {
            val synced = CalendarHelper.syncHearing(context, db, info, sms.id, "sms", sms.body)
            Log.d(TAG, "SmsProcessor: calendar synced=$synced")
        }

        // 提取URL
        val urls = TextParser.extractUrls(sms.body)
        Log.d(TAG, "SmsProcessor: found ${urls.size} urls: $urls")

        if (urls.isNotEmpty()) {
            // 先尝试使用 PdfDownloader 直接下载（适用于直接PDF链接）
            var webViewNeeded = false

            for (url in urls) {
                try {
                    // 检查是否是SPA页面（包含hash路由）
                    val isSpa = url.contains("#") ||
                                 url.contains("/#/") ||
                                 url.contains("zxfw.court.gov.cn") ||
                                 url.contains("wenshu.court.gov.cn")

                    if (isSpa) {
                        // SPA页面需要WebView渲染
                        webViewNeeded = true
                        Log.d(TAG, "SmsProcessor: SPA page detected, will use WebView: $url")
                        // 保存为待下载记录
                        PdfDownloader.savePendingUrlSync(db, sms.id, url, "需要WebView加载")
                    } else {
                        // 尝试直接下载
                        Log.d(TAG, "SmsProcessor: attempting direct download from $url")
                        PdfDownloader.downloadFromUrls(context, db, sms.id, listOf(url))
                    }
                } catch (e: Exception) {
                    Log.e(TAG, "SmsProcessor: error processing url=$url", e)
                    // 失败时也标记为需要WebView
                    webViewNeeded = true
                }
            }

            // 如果有需要WebView的URL，启动WebView处理
            if (webViewNeeded) {
                withContext(Dispatchers.Main) {
                    // 只启动第一个需要WebView的URL
                    val pendingUrl = urls.firstOrNull { url ->
                        url.contains("#") || url.contains("/#/") ||
                        url.contains("zxfw.court.gov.cn")
                    }
                    if (pendingUrl != null) {
                        val intent = Intent(context, com.shanfuchun.courtassistant.ui.WebViewActivity::class.java).apply {
                            putExtra("url", pendingUrl)
                            putExtra("smsId", sms.id)
                            putExtra("autoMode", true)
                            addFlags(Intent.FLAG_ACTIVITY_NEW_TASK)
                        }
                        try {
                            context.startActivity(intent)
                            Log.d(TAG, "SmsProcessor: started WebView for $pendingUrl")
                        } catch (e: Exception) {
                            Log.e(TAG, "SmsProcessor: failed to start WebView", e)
                        }
                    }
                }
            }
        }

        // 重新读取，避免覆盖 PdfParser 设置的 hasSummons
        val updated = db.smsDao().getById(sms.id) ?: sms
        db.smsDao().update(updated.copy(
            parseStatus = 1,
            courtName = info.courtName.ifEmpty { updated.courtName },
            partyName = info.partyName.ifEmpty { updated.partyName }
        ))
    }
}

