package com.shanfuchun.courtassistant.service

import android.app.Service
import android.content.Intent
import android.os.IBinder
import android.util.Log
import androidx.core.app.NotificationCompat
import androidx.core.app.NotificationManagerCompat
import com.shanfuchun.courtassistant.App
import com.shanfuchun.courtassistant.R
import com.shanfuchun.courtassistant.data.SmsRecord
import com.shanfuchun.courtassistant.sms.SmsProcessor
import kotlinx.coroutines.CoroutineScope
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.cancel
import kotlinx.coroutines.launch

/**
 * 快捷同步服务
 * 处理通知栏点击的"立即同步"操作
 */
class QuickSyncService : Service() {
    private val serviceScope = CoroutineScope(Dispatchers.IO)
    private var currentNotificationId: Int = 0

    override fun onBind(intent: Intent?): IBinder? = null

    override fun onStartCommand(intent: Intent?, flags: Int, startId: Int): Int {
        intent?.extras?.let { extras ->
            val smsId = extras.getLong(EXTRA_SMS_ID, -1)
            val notificationId = extras.getInt(EXTRA_NOTIFICATION_ID, -1)
            val smsBody = extras.getString(EXTRA_SMS_BODY) ?: ""
            currentNotificationId = notificationId

            if (smsId > 0) {
                performQuickSync(smsId, smsBody, notificationId)
            }
        }
        return START_NOT_STICKY
    }

    private fun performQuickSync(smsId: Long, smsBody: String, notificationId: Int) {
        serviceScope.launch {
            try {
                // 显示处理中通知
                showProcessingNotification()

                val app = application as App
                val sms = app.db.smsDao().getById(smsId)

                if (sms != null) {
                    // 执行同步处理
                    SmsProcessor.process(applicationContext, app.db, sms)

                    // 显示成功通知
                    showSuccessNotification(sms)
                } else {
                    Log.e(TAG, "SMS record not found: $smsId")
                }
            } catch (e: Exception) {
                Log.e(TAG, "Quick sync failed", e)
                showErrorNotification(e.message ?: "同步失败")
            } finally {
                // 停止服务
                stopSelf()
            }
        }
    }

    private fun showProcessingNotification() {
        val notification = NotificationCompat.Builder(this, App.CHANNEL_ID)
            .setSmallIcon(R.mipmap.ic_launcher)
            .setContentTitle("12368 法院通知")
            .setContentText("正在同步开庭信息...")
            .setOngoing(true)
            .setProgress(0, 0, true)
            .build()

        startForeground(PROCESSING_NOTIFICATION_ID, notification)
    }

    private fun showSuccessNotification(sms: SmsRecord) {
        // 取消处理中通知
        NotificationManagerCompat.from(this).cancel(PROCESSING_NOTIFICATION_ID)

        val notification = NotificationCompat.Builder(this, App.CHANNEL_ID)
            .setSmallIcon(R.mipmap.ic_launcher)
            .setContentTitle("同步成功")
            .setContentText("开庭信息已同步到日历")
            .setAutoCancel(true)
            .build()

        NotificationManagerCompat.from(this).notify(NOTIFICATION_SUCCESS_ID, notification)
    }

    private fun showErrorNotification(error: String) {
        // 取消处理中通知
        NotificationManagerCompat.from(this).cancel(PROCESSING_NOTIFICATION_ID)

        val notification = NotificationCompat.Builder(this, App.CHANNEL_ID)
            .setSmallIcon(R.mipmap.ic_launcher)
            .setContentTitle("同步失败")
            .setContentText(error)
            .setAutoCancel(true)
            .build()

        NotificationManagerCompat.from(this).notify(NOTIFICATION_ERROR_ID, notification)
    }

    override fun onDestroy() {
        super.onDestroy()
        serviceScope.cancel()
    }

    companion object {
        private const val TAG = "QuickSyncService"
        const val EXTRA_SMS_ID = "sms_id"
        const val EXTRA_NOTIFICATION_ID = "notification_id"
        const val EXTRA_SMS_BODY = "sms_body"

        private const val PROCESSING_NOTIFICATION_ID = 10001
        private const val NOTIFICATION_SUCCESS_ID = 10002
        private const val NOTIFICATION_ERROR_ID = 10003
    }
}

