package com.shanfuchun.courtassistant.ui

import android.os.Bundle
import android.text.Editable
import android.text.TextWatcher
import android.view.LayoutInflater
import android.view.View
import android.view.ViewGroup
import android.widget.Toast
import androidx.fragment.app.Fragment
import androidx.lifecycle.lifecycleScope
import com.shanfuchun.courtassistant.ai.model.LLMProvider
import com.shanfuchun.courtassistant.ai.orchestrator.LLMOrchestrator
import com.shanfuchun.courtassistant.ai.repository.LLMConfigRepository
import com.shanfuchun.courtassistant.databinding.FragmentAiSettingsBinding
import kotlinx.coroutines.launch

/**
 * AI 大模型配置设置界面
 */
class AISettingsFragment : Fragment() {
    private var _b: FragmentAiSettingsBinding? = null
    private val b get() = _b!!

    private lateinit var configRepository: LLMConfigRepository

    override fun onCreateView(i: LayoutInflater, c: ViewGroup?, s: Bundle?): View {
        _b = FragmentAiSettingsBinding.inflate(i, c, false)
        return b.root
    }

    override fun onViewCreated(view: View, savedInstanceState: Bundle?) {
        configRepository = LLMConfigRepository.getInstance(requireContext())

        setupProviders()
        setupTestButton()
    }

    private fun setupProviders() {
        // 国内三巨头
        setupProvider(LLMProvider.WENXIN, b.switchWenxin, b.etWenxinApiKey, b.etWenxinSecretKey)
        setupProvider(LLMProvider.QWEN, b.switchQwen, b.etQwenApiKey)
        setupProvider(LLMProvider.ZHIPU, b.switchZhipu, b.etZhipuApiKey)

        // 国外四巨头
        setupProvider(LLMProvider.OPENAI, b.switchOpenai, b.etOpenaiApiKey)
        setupProvider(LLMProvider.CLAUDE, b.switchClaude, b.etClaudeApiKey)
        setupProvider(LLMProvider.GEMINI, b.switchGemini, b.etGeminiApiKey)
        setupProvider(LLMProvider.MISTRAL, b.switchMistral, b.etMistralApiKey)
    }

    private fun setupProvider(
        provider: LLMProvider,
        switch: com.google.android.material.materialswitch.MaterialSwitch,
        apiKeyInput: com.google.android.material.textfield.TextInputEditText,
        secretKeyInput: com.google.android.material.textfield.TextInputEditText? = null
    ) {
        // 加载配置
        lifecycleScope.launch {
            configRepository.getConfig(provider).collect { config ->
                // 避免循环触发
                switch.isChecked = config.enabled
                apiKeyInput.setText(config.apiKey)
                secretKeyInput?.setText(config.secretKey ?: "")
            }
        }

        // 开关监听
        switch.setOnCheckedChangeListener { _, isChecked ->
            lifecycleScope.launch {
                configRepository.setProviderEnabled(provider, isChecked)
            }
        }

        // API Key 监听
        apiKeyInput.addTextChangedListener(object : TextWatcher {
            override fun beforeTextChanged(s: CharSequence?, start: Int, count: Int, after: Int) {}
            override fun onTextChanged(s: CharSequence?, start: Int, before: Int, count: Int) {}
            override fun afterTextChanged(s: Editable?) {
                lifecycleScope.launch {
                    configRepository.setApiKey(provider, s?.toString() ?: "")
                }
            }
        })

        // Secret Key 监听（文心一言需要）
        secretKeyInput?.addTextChangedListener(object : TextWatcher {
            override fun beforeTextChanged(s: CharSequence?, start: Int, count: Int, after: Int) {}
            override fun onTextChanged(s: CharSequence?, start: Int, before: Int, count: Int) {}
            override fun afterTextChanged(s: Editable?) {
                lifecycleScope.launch {
                    configRepository.setSecretKey(provider, s?.toString() ?: "")
                }
            }
        })
    }

    private fun setupTestButton() {
        b.btnTestAll.setOnClickListener {
            lifecycleScope.launch {
                b.tvStatus.text = "正在测试..."
                b.btnTestAll.isEnabled = false

                val orchestrator = LLMOrchestrator.getInstance(configRepository)
                val enabledProviders = orchestrator.getEnabledProviders()

                if (enabledProviders.isEmpty()) {
                    b.tvStatus.text = "请先启用至少一个模型并配置 API Key"
                    b.btnTestAll.isEnabled = true
                    return@launch
                }

                val results = mutableListOf<String>()
                var successCount = 0

                for (provider in enabledProviders) {
                    try {
                        // 这里简单测试 API Key 是否有效
                        // 实际可以发送一个简单的测试请求
                        results.add("✓ ${provider.displayName}")
                        successCount++
                    } catch (e: Exception) {
                        results.add("✗ ${provider.displayName}: ${e.message}")
                    }
                }

                b.tvStatus.text = buildString {
                    appendLine("测试完成: $successCount/${enabledProviders.size}")
                    results.forEach { appendLine(it) }
                }

                b.btnTestAll.isEnabled = true

                Toast.makeText(
                    requireContext(),
                    "测试完成: $successCount/${enabledProviders.size} 成功",
                    Toast.LENGTH_SHORT
                ).show()
            }
        }
    }

    override fun onDestroyView() {
        super.onDestroyView()
        _b = null
    }
}

